Javascript.validate:
var ec = null;
var courtCode = Services.getValue(OriginatingCourtCode.dataBinding);
if( null != courtCode && "" != courtCode)
{
	var xpathName = REF_DATA_XPATH + "/Courts/Court[./Code = " + OriginatingCourtCode.dataBinding + "]/Name";	 
	var courtName = Services.getValue(xpathName);
	if( null == courtName || "" == courtName)
	{
		ec = ErrorCode.getErrorCode('CaseMan_invalidCourtCode_Msg');
	}
}
return ec;

Javascript.logic:
var courtCode = Services.getValue(OriginatingCourtCode.dataBinding);
if( null != courtCode && "" != courtCode)
{
	var xpathName = REF_DATA_XPATH + "/Courts/Court[./Code = " + OriginatingCourtCode.dataBinding + "]/Name";	 
	var courtName = Services.getValue(xpathName);
	Services.setValue(OriginatingCourtName.dataBinding, courtName);
}
else
{
	Services.setValue(OriginatingCourtName.dataBinding, "");
}

Javascript.miscCode:
		
			function OriginatingCourtName(){}
			OriginatingCourtName.strictValidation = true;
			OriginatingCourtName.dataBinding = "/ds/EnterVariableData/cfotransfer/originatingcourt/name";
			OriginatingCourtName.tabIndex = __tabIdx++;
			OriginatingCourtName.helpText = "Originating court name";
			OriginatingCourtName.isMandatory = function() { return true; }
			OriginatingCourtName.srcData = REF_DATA_XPATH + "/Courts";
			OriginatingCourtName.rowXPath = "Court";
			OriginatingCourtName.keyXPath = "Name";
			OriginatingCourtName.displayXPath = "Name";

			OriginatingCourtName.logicOn = [OriginatingCourtName.dataBinding];
			OriginatingCourtName.logic = function() {   
				var name = Services.getValue(OriginatingCourtName.dataBinding);		     		
				if( null != name && "" != name)
				{
					var xpathCode = REF_DATA_XPATH + "/Courts/Court[./Name = " + OriginatingCourtName.dataBinding + "]/Code";	 
					var courtCode = Services.getValue(xpathCode);
					Services.setValue(OriginatingCourtCode.dataBinding, courtCode);
				}
				else
				{
					Services.setValue(OriginatingCourtCode.dataBinding, "");
				}
			}

			function OriginatingCourtLOVButton() {}
			OriginatingCourtLOVButton.tabIndex = __tabIdx++;

			function OriginatingCourtLOVGrid() {};
			OriginatingCourtLOVGrid.dataBinding = "/ds/var/page/SelectedLOVRow/OriginatingCourt";
			OriginatingCourtLOVGrid.srcData = REF_DATA_XPATH + "/Courts";
			OriginatingCourtLOVGrid.rowXPath = "Court";
			OriginatingCourtLOVGrid.keyXPath = "Code";
			OriginatingCourtLOVGrid.columns = [	{xpath: "Code"}, {xpath: "Name"} ];
			OriginatingCourtLOVGrid.logicOn = [OriginatingCourtLOVGrid.dataBinding];
			OriginatingCourtLOVGrid.logic = function() 
			{
				var id = Services.getValue(OriginatingCourtLOVGrid.dataBinding);
				Services.setValue(OriginatingCourtCode.dataBinding, id);
			} 

			OriginatingCourtLOVGrid.raise = {
				eventBinding: {
					singleClicks: [ {element: "OriginatingCourtLOVButton"} ],
					keys: [ { key: Key.F6, element: "OriginatingCourtCode" }, { key: Key.F6, element: "OriginatingCourtName" } ]
				}
			};
